class UrlValidator {

    private static final Set<String> ALLOWED_SCHEMES = Set.of("https");

    private static final List<String> ALLOWED_DOMAINS = List.of(
            "api.partner1.com",
            "api.partner2.com",
            "webhook.partner3.com"
    );

    private static final long MAX_CONTENT_LENGTH = 10 * 1024 * 1024; // 10 MB

    public void validate(String urlString) throws UrlValidationException {
        if (urlString == null || urlString.isBlank()) {
            throw new UrlValidationException("URL must not be empty");
        }

        URI uri;
        try {
            uri = new URI(urlString);
        } catch (URISyntaxException e) {
            throw new UrlValidationException("Invalid URL syntax");
        }

        // Validate scheme
        String scheme = uri.getScheme();
        if (scheme == null || !ALLOWED_SCHEMES.contains(scheme.toLowerCase())) {
            throw new UrlValidationException("Only HTTPS URLs are allowed");
        }

        // Validate host exists
        String host = uri.getHost();
        if (host == null || host.isBlank()) {
            throw new UrlValidationException("URL must contain a valid host");
        }

        // Validate against allowlist of domains
        if (!isAllowedDomain(host)) {
            throw new UrlValidationException("Domain is not in the allowed list of partner domains");
        }

        // Validate port
        int port = uri.getPort();
        if (port != -1 && port != 443) {
            throw new UrlValidationException("Only standard HTTPS port (443) is allowed");
        }

        // Prevent SSRF: resolve hostname and check it's not a private/internal IP
        validateNotInternalAddress(host);

        // Check for user info in URL (potential credential leakage)
        if (uri.getUserInfo() != null) {
            throw new UrlValidationException("URLs with embedded credentials are not allowed");
        }

        // Prevent path traversal patterns
        String path = uri.getPath();
        if (path != null && (path.contains("..") || path.contains("//") || path.contains("\\") || path.contains("%2e") || path.contains("%2E"))) {
            throw new UrlValidationException("URL path contains disallowed characters");
        }
    }

    private boolean isAllowedDomain(String host) {
        String normalizedHost = host.toLowerCase();
        for (String allowed : ALLOWED_DOMAINS) {
            if (normalizedHost.equals(allowed)) {
                return true;
            }
        }
        return false;
    }

    private void validateNotInternalAddress(String host) throws UrlValidationException {
        try {
            InetAddress[] addresses = InetAddress.getAllByName(host);
            for (InetAddress address : addresses) {
                if (address.isLoopbackAddress() ||
                        address.isSiteLocalAddress() ||
                        address.isLinkLocalAddress() ||
                        address.isAnyLocalAddress() ||
                        address.isMulticastAddress() ||
                        isPrivateIPv6(address)) {
                    throw new UrlValidationException("URL resolves to a private or internal IP address");
                }
            }
        } catch (UnknownHostException e) {
            throw new UrlValidationException("Unable to resolve hostname: " + host);
        }
    }

    private boolean isPrivateIPv6(InetAddress address) {
        byte[] bytes = address.getAddress();
        if (bytes.length == 16) {
            // Check for ::1 (loopback)
            // Check for fc00::/7 (unique local)
            // Check for fe80::/10 (link local)
            return (bytes[0] & 0xFE) == 0xFC || // fc00::/7
                    (bytes[0] == (byte) 0xFE && (bytes[1] & 0xC0) == 0x80); // fe80::/10
        }
        return false;
    }
}

class UrlValidationException extends Exception {
    public UrlValidationException(String message) {
        super(message);
    }
}

@RestController
@RequestMapping("/api/webhook")
class WebhookController {

    private final RestTemplate restTemplate;
    private final UrlValidator urlValidator;

    public WebhookController(RestTemplate restTemplate, UrlValidator urlValidator) {
        this.restTemplate = restTemplate;
        this.urlValidator = urlValidator;
    }

    @PostMapping("/fetch")
    public ResponseEntity<WebhookResponse> handleWebhook(
            @Valid @RequestBody WebhookRequest request,
            @RequestHeader(value = "X-Webhook-Secret", required = true) String webhookSecret) {

        // Validate webhook secret (use constant-time comparison)
        if (!isValidWebhookSecret(webhookSecret)) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                    .body(new WebhookResponse(request.getCallbackId(), 401, null, "Unauthorized"));
        }

        // Validate and sanitize the URL
        try {
            urlValidator.validate(request.getUrl());
        } catch (UrlValidationException e) {
            return ResponseEntity.badRequest()
                    .body(new WebhookResponse(request.getCallbackId(), 400, null, e.getMessage()));
        }

        // Fetch content from the validated URL
        try {
            ResponseEntity<String> response = restTemplate.getForEntity(request.getUrl(), String.class);

            String content = response.getBody();
            // Limit response size
            if (content != null && content.length() > 10 * 1024 * 1024) {
                return ResponseEntity.status(HttpStatus.PAYLOAD_TOO_LARGE)
                        .body(new WebhookResponse(request.getCallbackId(), 413, null, "Response too large"));
            }

            return ResponseEntity.ok(
                    new WebhookResponse(request.getCallbackId(), response.getStatusCode().value(), content, null));

        } catch (Exception e) {
            // Don't leak internal error details to the caller
            return ResponseEntity.status(HttpStatus.BAD_GATEWAY)
                    .body(new WebhookResponse(request.getCallbackId(), 502, null, "Failed to fetch content from the provided URL"));
        }
    }

    @GetMapping("/health")
    public ResponseEntity<Map<String, String>> health() {
        return ResponseEntity.ok(Map.of("status", "UP"));
    }

    private boolean isValidWebhookSecret(String secret) {
        // In production, load from environment variable or secrets manager
        String expectedSecret = System.getenv("WEBHOOK_SECRET");
        if (expectedSecret == null || secret == null) {
            return false;
        }
        // Constant-time comparison to prevent timing attacks
        return java.security.MessageDigest.isEqual(
                expectedSecret.getBytes(java.nio.charset.StandardCharsets.UTF_8),
                secret.getBytes(java.nio.charset.StandardCharsets.UTF_8));
    }
}

